import { promises as fsp2 } from "fs";
var ClaudeConfigCommand = class {
  constructor(claudeConfigService) {
    this.claudeConfigService = claudeConfigService;
  }
  /**
   * Remove stale worktree folder registrations from ~/.claude.json.
   */
  async clean(options = {}) {
    try {
      if (options.dryRun) {
        console.log("\u{1F50D} Scanning for stale worktree registrations...\n");
        const registrations = await this.claudeConfigService.listWorktreeRegistrations();
        if (registrations.length === 0) {
          console.log("No worktree registrations found in ~/.claude.json");
          return;
        }
        console.log(`Found ${registrations.length} worktree registration(s):
`);
        let staleCount = 0;
        for (const regPath of registrations) {
          try {
            await fsp2.access(regPath);
            console.log(`  \u2713 ${regPath} (exists)`);
          } catch {
            console.log(`  \u2717 ${regPath} (stale - would be removed)`);
            staleCount++;
          }
        }
        console.log();
        if (staleCount > 0) {
          console.log(`Would remove ${staleCount} stale registration(s).`);
          console.log("Run without --dry-run to apply changes.");
        } else {
          console.log("No stale registrations found.");
        }
        return;
      }
      console.log("\u{1F9F9} Cleaning stale worktree registrations from ~/.claude.json...\n");
      const result = await this.claudeConfigService.cleanStaleWorktrees();
      if (!result.success) {
        console.error(`\u274C ${result.message}`);
        process.exit(1);
      }
      if (result.removedCount === 0) {
        console.log("\u2713 No stale registrations found.");
      } else {
        console.log(`\u2713 Removed ${result.removedCount} stale registration(s):
`);
        for (const removedPath of result.removedPaths) {
          console.log(`  - ${removedPath}`);
        }
      }
    } catch (error48) {
      console.error(`\u274C Error: ${error48 instanceof Error ? error48.message : String(error48)}`);
      process.exit(1);
    }
  }
};

